#!/usr/bin/env python3
"""
Move files generated by mdsplit into the appropriate subfolders.
Matches if the filename starts with a known prefix.
Also fixes filenames that start with a dash (e.g., -real-world-impact.md).

With mdsplit -l 3, files land in mkdocs/ as:
  - ##-level wrapper files (already had prefix stripped by cleanup_mdsplit.py):
      e.g. reslava.result-core-library.md
  - ###-level files (prefix intact from mdsplit slugification):
      e.g. 7.1.-Operations.md

  The section-number prefixes (e.g. "7.1.-") are stripped IN-PLACE after routing,
  producing stable clean filenames (e.g. Operations.md → lowercased later to operations.md).
"""

import re
import shutil
from pathlib import Path

DOCS_DIR = Path("mkdocs")

# Mapping: prefix (lowercase) → destination folder.
# Section-number entries ("7.", "8.", ...) route ###-level mdsplit files.
# Content-name entries route ##-level wrapper files (prefix already stripped).
# Longest-first matching: more-specific entries win over shorter ones.
MAPPING = {
    # ── Section-number routing (###-level files from mdsplit -l 3) ──────────
    # Numbers map to the same destinations as the ## section they belong to.
    "7.":  "core-concepts/result",
    "8.":  "core-concepts/error-types",
    "9.":  "core-concepts/validation",
    "10.": "core-concepts/advanced-types",
    "11.": "core-concepts/advanced-types",
    "12.": "aspnet/smartendpoints",
    "13.": "aspnet",
    "14.2.": "architecture/source-generators",
    "14.5.": "architecture/source-generators",
    "14.6.": "architecture/source-generators",
    "14.7.": "architecture/source-generators",
    "14.": "architecture",
    "15.2.": "architecture/source-generators",
    "15.3.": "architecture/source-generators",
    "15.": "architecture",
    "16.": "architecture/source-generators",
    "17.": "code-examples",
    "18.": "testing",
    "19.": "safety-analyzers",
    "20.": "testing",
    "21.": "reference",
    "22.": "reference",
    "23.": "community",
    "24.": "community",
    "25.": "community",
    "26.": "community",
    "6.":  "getting-started/the-transformation",
    "5.":  "getting-started",
    "4.":  "getting-started/quick-start-scenarios",
    "3.":  "getting-started",
    "2.":  "getting-started/installation",

    # ── Content-name routing (##-level wrapper files + legacy flat names) ────
    # Getting Started
    "getting-started": "getting-started",
    "installation": "getting-started/installation",
    "choose-your-path": "getting-started",
    "the-transformation": "getting-started/the-transformation",
    "quick-start-scenarios": "getting-started/quick-start-scenarios",
    "quick-start": "getting-started",

    # Core Concepts — result subfolder
    "reslava.result-core-library": "core-concepts/result",
    "result-pattern": "core-concepts/result",
    "functional-composition": "core-concepts/result",
    "async-patterns": "core-concepts/result",
    "linq-integration": "core-concepts/result",
    "performance": "core-concepts/result",
    "advanced-patterns": "core-concepts/result",
    "core-concepts": "core-concepts",

    # Core Concepts — error-types subfolder
    "domain-errors": "core-concepts/error-types",
    "error-context": "core-concepts/error-types",
    "error-types": "core-concepts/error-types",

    # Core Concepts — validation subfolder
    "validation-attributes": "core-concepts/validation",
    "validation-rules": "core-concepts/validation",
    "validation": "core-concepts/validation",

    # Core Concepts — advanced-types subfolder
    "maybe": "core-concepts/advanced-types",
    "oneof": "core-concepts/advanced-types",

    # Code examples
    "quick-examples": "code-examples",
    "sample-apps": "code-examples",
    "examples": "code-examples/samples",

    # ASP.NET — smartendpoints subfolder
    "smartendpoints": "aspnet/smartendpoints",
    "oneof-to-iresult": "aspnet/smartendpoints",
    "one-of-to-iresult": "aspnet/smartendpoints",
    "oneof--iresult": "aspnet/smartendpoints",      # mdsplit strips → character
    "openapi": "aspnet/smartendpoints",
    "authorization": "aspnet/smartendpoints",

    # ASP.NET — general
    "aspnet": "aspnet",
    "asp.net-integration": "aspnet",                # note: original had dot
    "minimal-api": "aspnet",
    "mvc": "aspnet",
    "problem-details": "aspnet",
    "http-client": "aspnet",

    # Architecture
    "architecture": "architecture",
    "complete-architecture": "architecture",
    "package-structure": "architecture",
    "how-generators-work": "architecture/source-generators",
    "reslava.result.sourcegenerators": "architecture/source-generators",
    "generators": "architecture/source-generators",
    "solid-architecture": "architecture/solid",
    "uml-v1.12.1-core": "architecture/solid",
    "uml-v1.12.1-generators": "architecture/solid",
    "uml-v1.25.0-core": "architecture/solid",
    "uml-v1.25.0-generators": "architecture/solid",

    # Safety Analyzers
    "safety-analyzers": "safety-analyzers",
    "roslyn-analyzers": "safety-analyzers",

    # Testing & Quality
    "testing": "testing",
    "test-suite": "testing",
    "ci-cd": "testing",
    "real-world-impact": "testing",
    "production-benefits": "testing",

    # Reference
    "reference": "reference",
    "version-history": "reference",
    "roadmap": "reference",
    "overview": "reference/api-doc",

    # Community
    "contributing": "community",
    "contributors": "community",
    "license": "community",
    "acknowledgments": "community",

    # Others (catch-all if needed, but better to be explicit)
    "why-choose-reslava.result": "testing",         # moved to testing/production-benefits
}

# Regex to strip the ###-level section-number prefix AFTER routing.
# Examples: "7.1.-"  →  ""   |   "9.6.--"  →  ""   |   "12.4.--"  →  ""
# Does NOT match ##-level prefixes (already stripped by cleanup_mdsplit.py).
_H3_PREFIX_RE = re.compile(r'^\d+\.[\d.]*-+')


def strip_h3_prefix(stem):
    """Remove mdsplit ###-level section-number prefix from a file stem."""
    return _H3_PREFIX_RE.sub('', stem)


def fix_dash_filenames(docs_dir):
    """Rename any file starting with '-' to remove the leading dash."""
    for file in docs_dir.glob("*.md"):
        if file.name.startswith('-'):
            new_name = file.name.lstrip('-')
            new_path = file.with_name(new_name)
            print(f"✂️  Renaming {file.name} → {new_name}")
            file.rename(new_path)


def main():
    if not DOCS_DIR.exists():
        print("❌ docs/ directory not found.")
        return

    # First, fix filenames that start with a dash
    fix_dash_filenames(DOCS_DIR)

    # Collect all markdown files (excluding index.md)
    files = [f for f in DOCS_DIR.glob("*.md") if f.name != "index.md"]

    for file in files:
        stem = file.stem.lower()
        matched = False

        # Try to find a matching prefix (longest first)
        for prefix in sorted(MAPPING.keys(), key=len, reverse=True):
            if stem.startswith(prefix):
                dest_folder = DOCS_DIR / MAPPING[prefix]
                dest_folder.mkdir(parents=True, exist_ok=True)
                dest_path = dest_folder / file.name
                print(f"Moving {file.name} → {MAPPING[prefix]}/")
                shutil.move(str(file), str(dest_path))

                # Strip the ###-level section-number prefix in-place after routing.
                # This turns e.g. "7.1.-Operations.md" → "Operations.md" (stable clean URL).
                # ##-level files (already stripped) are unaffected (no match).
                new_stem = strip_h3_prefix(dest_path.stem)
                if new_stem and new_stem != dest_path.stem:
                    new_path = dest_path.with_name(new_stem + dest_path.suffix)
                    if not new_path.exists():
                        dest_path.rename(new_path)
                        print(f"  Renamed {dest_path.name} → {new_path.name}")
                    else:
                        print(f"  ⚠️ Skip rename {dest_path.name}: {new_path.name} already exists")

                matched = True
                break

        if not matched:
            print(f"⚠️  Warning: No matching prefix for {file.name}, leaving in mkdocs/")

if __name__ == "__main__":
    main()
